output.output:
=== TOP-LEVEL KEYS ===
['config', 'data', 'mark', 'encoding', 'height', 'params', 'title', 'transform', 'width', '$schema']

=== DATA ===
{
  "url": "https://vega.github.io/vega-datasets/data/population.json"
}

=== MARK ===
{'type': 'bar'}

=== TRANSFORMS ===
{
  "calculate": "datum.sex === 1 ? -datum.people : datum.people",
  "as": "signed_people"
}
{
  "filter": "datum.year == year_param"
}

=== ENCODINGS ===
X: {
  "axis": {
    "format": "~s",
    "labelExpr": "abs(datum.value)"
  },
  "field": "signed_people",
  "title": "Population",
  "type": "quantitative"
}
Y: {
  "field": "age",
  "sort": "descending",
  "title": "Age",
  "type": "ordinal"
}
Color: {
  "field": "sex",
  "legend": {
    "labelExpr": "datum.value == 1 ? 'Male' : 'Female'",
    "title": "Sex"
  },
  "scale": {
    "domain": [
      1,
      2
    ],
    "range": [
      "steelblue",
      "salmon"
    ]
  },
  "type": "nominal"
}

=== PARAMS ===
{
  "name": "year_param",
  "bind": {
    "input": "select",
    "options": [
      1850,
      1860,
      1870,
      1880,
      1890,
      1900,
      1910,
      1920,
      1930,
      1940,
      1950,
      1960,
      1970,
      1980,
      1990,
      2000
    ],
    "name": "Census year: "
  },
  "value": 1980
}
